(In reply to Žilvinas Žaltiena from comment #7)
Thank you for testing.  Did the panic happen right away?

I was afraid of this: kerberos is able to generate crypto requests that cannot be handled by the QAT driver (there are some constraints which can cause requests to be rejected with E2BIG, i.e., error 7), and there is nothing which provides fallback to software encryption/decryption, and kerberos has no way to propagate errors to an upper layer.

So for now the only safe thing to do is disable hardware offloading of crypto ops:

diff --git a/sys/kgssapi/krb5/kcrypto_aes.c b/sys/kgssapi/krb5/kcrypto_aes.c
index 38faeb37066c..f97560f728c7 100644
--- a/sys/kgssapi/krb5/kcrypto_aes.c
+++ b/sys/kgssapi/krb5/kcrypto_aes.c
@@ -96,8 +96,7 @@ aes_set_key(struct krb5_key_state *ks, const void *in)
        csp.csp_auth_klen = ks->ks_class->ec_keybits / 8;
        csp.csp_auth_mlen = 12;
        csp.csp_auth_key = ks->ks_key;
-       crypto_newsession(&as->as_session_sha1, &csp,
-           CRYPTOCAP_F_HARDWARE | CRYPTOCAP_F_SOFTWARE);
+       crypto_newsession(&as->as_session_sha1, &csp, CRYPTOCAP_F_SOFTWARE);

        memset(&csp, 0, sizeof(csp));
        csp.csp_mode = CSP_MODE_CIPHER;
@@ -105,8 +104,7 @@ aes_set_key(struct krb5_key_state *ks, const void *in)
        csp.csp_cipher_klen = ks->ks_class->ec_keybits / 8;
        csp.csp_cipher_key = ks->ks_key;
        csp.csp_ivlen = 16;
-       crypto_newsession(&as->as_session_aes, &csp,
-           CRYPTOCAP_F_HARDWARE | CRYPTOCAP_F_SOFTWARE);
+       crypto_newsession(&as->as_session_aes, &csp, CRYPTOCAP_F_SOFTWARE);
 }

 static void
